import{describe as t,it as e,expect as o}from"vitest";import{stripAnsi as r,stringWidth as i,padString as n,createBorderLine as s,createContentLine as h}from"../utils/string-width.js";t("string-width utilities",()=>{t("stripAnsi",()=>{e("removes ANSI color codes",()=>{o(r("[31mred[0m")).toBe("red")}),e("returns plain string unchanged",()=>{o(r("hello")).toBe("hello")}),e("handles multi-segment colored strings",()=>{o(r("[1mbold[22m [36mcyan[39m")).toBe("bold cyan")})}),t("stringWidth",()=>{e("returns 1 per ASCII char",()=>{o(i("hello")).toBe(5)}),e("counts CJK as width 2",()=>{o(i("你好")).toBe(4)}),e("counts emoji as width 2",()=>{o(i("🚀")).toBe(2)}),e("strips ANSI before counting",()=>{o(i("[31mhi[0m")).toBe(2)}),e("returns 0 for zero-width characters",()=>{o(i("​")).toBe(0)}),e("handles fullwidth characters",()=>{o(i("Ａ")).toBe(2)})}),t("padString",()=>{e("pads to the right by default",()=>{o(n("hi",5)).toBe("hi   ")}),e("pads to the left when align=right",()=>{o(n("hi",5," ","right")).toBe("   hi")}),e("centers text",()=>{o(n("hi",6," ","center")).toBe("  hi  ")}),e("does not pad when string already wider than target",()=>{o(n("hello",3)).toBe("hello")}),e("uses custom pad char",()=>{o(n("x",4,"-")).toBe("x---")}),e("counts CJK width when padding",()=>{o(n("你",5)).toBe("你   ")})}),t("createBorderLine",()=>{e("creates a border with corners and fill",()=>{const t=s("+","+","-",5);o(t).toBe("+---+")}),e("does not produce negative width",()=>{const t=s("++","++","-",1);o(t).toBe("++++")})}),t("createContentLine",()=>{e("left-aligns content within borders",()=>{const t=h("hi","|","|",6);o(t).toBe("|hi  |")}),e("returns content within total width minus borders",()=>{const t=h("x","|","|",5);o(t).toBe("|x  |")})})});